import { useEffect } from 'react'
import { Toaster } from 'react-hot-toast'
import Navbar from './components/Navbar'
import Hero from './components/Hero'
import { About, Skills, Experience, GitHub, Devlog, Footer } from './components/Sections'
import Projects from './components/Projects'
import Systems from './components/Systems'
import Contact from './components/Contact'
import AICodingAgent from './components/AICodingAgent'

// Embed resume base64 — injected at build time
const RESUME_B64 = ''

function downloadResume() {
  try {
    const a = document.createElement('a')
    a.href = 'data:application/pdf;base64,' + RESUME_B64
    a.download = 'Yasar_Khan_GameDev_Resume.pdf'
    document.body.appendChild(a); a.click(); document.body.removeChild(a)
  } catch { window.open('mailto:msym5556@gmail.com?subject=Resume Request') }
}

export default function App() {
  // Read progress + back to top
  useEffect(() => {
    const onScroll = () => {
      const el = document.documentElement
      const pct = (window.scrollY / (el.scrollHeight - el.clientHeight)) * 100
      const rp = document.getElementById('rp')
      const btt = document.getElementById('btt')
      if (rp) rp.style.width = pct + '%'
      if (btt) btt.classList.toggle('show', window.scrollY > 500)
    }
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  return (
    <>
      {/* Progress bar */}
      <div id="rp" />

      {/* Navbar */}
      <Navbar onResume={downloadResume} />

      {/* Main */}
      <main>
        <Hero onResume={downloadResume} />
        <About onResume={downloadResume} />
        <Projects />
        <Systems />
        <Skills />
        <Experience />
        <GitHub />
        <Devlog />
        <AICodingAgent />
        <Contact onResume={downloadResume} />
      </main>

      <Footer />

      {/* Back to top */}
      <button id="btt" onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} aria-label="Back to top">↑</button>

      {/* Toast */}
      <Toaster position="bottom-center" toastOptions={{ duration: 3500 }} />
    </>
  )
}
